function resolveReferences(items = []) {
  return items.map((item) => ({ ...item, href: REFERENCE_URLS[item.key] }));
}

export function getTrustContent(language = "en") {
  const copy = TRUST_COPY[language] || TRUST_COPY.en;
  return {
    ...copy,
    about: { ...copy.about, sources: resolveReferences(copy.about.sources) },
    editorial: { ...copy.editorial, references: resolveReferences(copy.editorial.references) },
  };
}

export { REFERENCE_URLS };
